import React, { useState } from 'react';
import SEOHead from '../components/SEOHead';

const COLORS = [
  { name: 'Black',  hex: '#1a1a1a', digit: 0, multiplier: 1,      tolerance: null },
  { name: 'Brown',  hex: '#7B3F00', digit: 1, multiplier: 10,     tolerance: '±1%' },
  { name: 'Red',    hex: '#CC0000', digit: 2, multiplier: 100,    tolerance: '±2%' },
  { name: 'Orange', hex: '#FF8C00', digit: 3, multiplier: 1000,   tolerance: null },
  { name: 'Yellow', hex: '#FFD700', digit: 4, multiplier: 10000,  tolerance: null },
  { name: 'Green',  hex: '#228B22', digit: 5, multiplier: 100000, tolerance: '±0.5%' },
  { name: 'Blue',   hex: '#0000CD', digit: 6, multiplier: 1000000,tolerance: null },
  { name: 'Violet', hex: '#8B008B', digit: 7, multiplier: null,   tolerance: null },
  { name: 'Grey',   hex: '#808080', digit: 8, multiplier: null,   tolerance: null },
  { name: 'White',  hex: '#E8E8E8', digit: 9, multiplier: null,   tolerance: null },
  { name: 'Gold',   hex: '#CFB53B', digit: null, multiplier: 0.1, tolerance: '±5%' },
  { name: 'Silver', hex: '#C0C0C0', digit: null, multiplier: 0.01,tolerance: '±10%' },
];

const digitColors = COLORS.filter(c => c.digit !== null);
const multColors  = COLORS.filter(c => c.multiplier !== null);
const tolColors   = COLORS.filter(c => c.tolerance !== null);

const formatL = (uH) => {
  if (uH >= 1000000) return `${(uH/1000000).toFixed(3)} H`;
  if (uH >= 1000) return `${(uH/1000).toFixed(3)} mH`;
  return `${uH.toFixed(3)} µH`;
};

export default function InductorCode() {
  const [sel, setSel] = useState({ b1: 'Brown', b2: 'Black', b3: 'Black', b4: 'Gold' });
  const [result, setResult] = useState(null);

  const handleBand = (band, name) => { setSel(s => ({...s, [band]: name})); setResult(null); };

  const calculate = () => {
    const c = (name) => COLORS.find(c => c.name === name);
    const [b1,b2,b3,b4] = [c(sel.b1),c(sel.b2),c(sel.b3),c(sel.b4)];
    if (!b1||!b2||!b3||!b4) return;
    const uH = (b1.digit * 10 + b2.digit) * b3.multiplier;
    setResult({ uH, tol: b4.tolerance });
  };

  const ColorSelect = ({ bandKey, label, options }) => (
    <div className="input-group">
      <label>{label}</label>
      <div style={{display:'flex',gap:'8px',alignItems:'center'}}>
        <select value={sel[bandKey] || ''} onChange={e => handleBand(bandKey, e.target.value)} style={{flex:1}}>
          {options.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
        </select>
        <div style={{width:'28px',height:'28px',borderRadius:'6px',background:COLORS.find(c=>c.name===sel[bandKey])?.hex,border:'1px solid var(--border)',flexShrink:0}} />
      </div>
    </div>
  );

  return (
    <>
      <SEOHead
        title="Inductor Color Code Calculator – 4 Band | PoolCalculator"
        description="Decode 4-band inductor color codes instantly. Enter the colors to find the inductance in µH and tolerance percentage."
        keywords="inductor color code, inductance calculator, 4 band inductor, inductor value calculator"
        canonical="/inductor-code"
      />
      <div className="page-wrapper">
        <div className="container">
          <div className="ad-slot ad-slot-banner">Top Banner Advertisement</div>
          <div className="page-header">
            <h1>Inductor Color Code Calculator</h1>
            <p>Identify 4-band inductor values based on their color bands. Results are in Microhenries (µH).</p>
          </div>

          <div className="calc-layout">
            <div className="card">
              <div className="section-title">Color Band Selection</div>
              <ColorSelect bandKey="b1" label="Band 1 (1st digit)" options={digitColors} />
              <ColorSelect bandKey="b2" label="Band 2 (2nd digit)" options={digitColors} />
              <ColorSelect bandKey="b3" label="Band 3 (Multiplier)" options={multColors} />
              <ColorSelect bandKey="b4" label="Band 4 (Tolerance)" options={tolColors} />
              <button className="btn-primary" onClick={calculate} style={{marginTop:'12px'}}>Decode Inductor</button>
            </div>

            <div className="hero-image-container">
              <img src="/images/calculator_inductor.png" alt="Inductor Color Coding" className="hero-img" />
            </div>
          </div>

          {result && (
            <div className="result-section">
              <div className="card">
                <div className="section-title">Inductance Result</div>
                <div className="result-box">
                  <div className="result-item highlight">
                    <span className="result-label">Total Inductance</span>
                    <span className="result-value">{formatL(result.uH)}</span>
                  </div>
                  {result.tol && (
                    <div className="result-item">
                      <span className="result-label">Tolerance</span>
                      <span className="result-value" style={{color:'var(--warning)'}}>{result.tol}</span>
                    </div>
                  )}
                </div>
              </div>
              <div className="ad-slot ad-slot-banner">Below Result Advertisement</div>
            </div>
          )}

          <div className="description-section card">
            <div className="description-layout">
              <div className="description-image">
                <img src="/images/calculator_descrip_inductor.png" alt="How to read inductor bands" />
              </div>
              <div className="description-text">
                <div className="section-title">How to Read Inductor Color Codes</div>
                <p>
                  Inductor color coding is similar to resistor color coding. Most axial inductors use 4 bands. 
                  The result is typically in Microhenries (µH).
                </p>
                <div className="formula-box">
                  <h3>The Calculation</h3>
                  <p>Inductance (µH) = (Digit 1 Digit 2) × Multiplier</p>
                  <p style={{fontSize:'13px', marginTop:'6px', color:'var(--text-muted)'}}>Example: Red (2), Violet (7), Brown (×10), Gold (±5%) = 270 µH ±5%.</p>
                </div>
                <div className="example-box">
                  <h3>Note</h3>
                  <p>Axial inductors often look like resistors but have a slightly different body shape and are usually green or cyan in color.</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
